  // ═══ CACHE LAYER — Mengurangi query ke database ═══
  const _cache={};
  function cacheGet(key){const c=_cache[key];if(!c)return null;if(Date.now()-c.ts>c.ttl)return null;return c.data;}
  function cacheSet(key,data,ttlMs=60000){_cache[key]={data,ts:Date.now(),ttl:ttlMs};}
  function cacheClear(prefix){Object.keys(_cache).filter(k=>k.startsWith(prefix)).forEach(k=>delete _cache[k]);}

  // Toast helper - mengganti semua alert()
  function showT(msg,type="success"){setToast({msg,type});setTimeout(()=>setToast(null),3500);}

  // ═══ VALIDASI INPUT ═══
  const vEmail=e=>/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(e);
  const vPhone=p=>/^62\d{8,13}$/.test(p.replace(/[^0-9]/g,''));
  const vPass=p=>p.length>=6&&/[a-zA-Z]/.test(p)&&/[0-9]/.test(p);
  const vPrice=n=>!isNaN(n)&&parseInt(n)>=1000;
  const vStock=n=>!isNaN(n)&&parseInt(n)>=1;
  const vAmount=n=>!isNaN(n)&&parseFloat(n)>=1;

  // ═══ RATE LIMITING ═══
  const rlStore={};
  function checkRL(action,maxPerDay){
    const key=`${user?.id}_${action}`;const now=Date.now();
    if(!rlStore[key])rlStore[key]=[];
    rlStore[key]=rlStore[key].filter(t=>now-t<86400000);
    if(rlStore[key].length>=maxPerDay){showT(`⚠️ Batas harian tercapai (maks ${maxPerDay}/${action.replace(/_/g," ")} per hari)`,"error");return false;}
    rlStore[key].push(now);return true;
  }

  // Disclaimer
  const [showDisclaimer,setShowDisclaimer]=useState(false);

  // File Upload ke Supabase Storage
  async function uploadFile(file,folder="products"){
    if(!file||!user)return null;
    setUploading(true);
    try{
      const ext=file.name.split('.').pop();
      const path=`${user.id}/${folder}/${Date.now()}.${ext}`;
      const{error}=await getSupabase()?.storage.from('uploads').upload(path,file);
      if(error){showT("Upload gagal: "+error.message,"error");setUploading(false);return null;}
      const{data}=getSupabase()?.storage.from('uploads').getPublicUrl(path);
      setUploading(false);
      return data.publicUrl;
    }catch(e){setUploading(false);showT("Upload error","error");return null;}
  }

  // Chat functions
  async function fetchChatList(){
    if(!user)return;
    // Get unique chat partners
    const{data}=await getSupabase()?.from('chat_messages').select('sender_id,receiver_id,message,created_at,sender:profiles!sender_id(full_name),receiver:profiles!receiver_id(full_name)').or(`sender_id.eq.${user.id},receiver_id.eq.${user.id}`).order('created_at',{ascending:false}).limit(100);
    if(!data)return;
    const partners={};
    data.forEach(m=>{
      const pid=m.sender_id===user.id?m.receiver_id:m.sender_id;
      const pname=m.sender_id===user.id?m.receiver?.full_name:m.sender?.full_name;
      if(!partners[pid])partners[pid]={id:pid,name:pname,lastMsg:m.message,time:m.created_at};
    });
    setChatList(Object.values(partners));
  }
  async function openChat(partnerId,partnerName){
    setChatOpen({id:partnerId,name:partnerName});setChatInput("");
    const{data}=await getSupabase()?.from('chat_messages').select('*,sender:profiles!sender_id(full_name)').or(`and(sender_id.eq.${user.id},receiver_id.eq.${partnerId}),and(sender_id.eq.${partnerId},receiver_id.eq.${user.id})`).order('created_at',{ascending:true}).limit(100);
    setChatMessages(data||[]);
    // Mark as read
    await getSupabase()?.from('chat_messages').update({read:true}).eq('receiver_id',user.id).eq('sender_id',partnerId);
    // Subscribe to realtime
    const channel=getSupabase()?.channel('chat-'+partnerId).on('postgres_changes',{event:'INSERT',schema:'public',table:'chat_messages',filter:`sender_id=eq.${partnerId}`},(payload)=>{
      setChatMessages(prev=>[...prev,payload.new]);
    }).subscribe();
    return()=>channel?.unsubscribe();
  }
  async function sendChat(){
    if(!chatInput.trim()||!chatOpen||!user)return;
    const{data}=await getSupabase()?.from('chat_messages').insert({sender_id:user.id,receiver_id:chatOpen.id,message:chatInput.trim()}).select().single();
    if(data)setChatMessages(prev=>[...prev,data]);
    setChatInput("");
  }

