{page==="hibah"&&<div style={{maxWidth:1280,margin:"0 auto",padding:"28px 24px 64px"}}><button className="back" onClick={()=>nav("home")}>← Beranda</button><h1 className="hlg" style={{marginBottom:4}}>🎁 Hibah Barkas</h1><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:16,flexWrap:"wrap",gap:8}}><p style={{color:"#aaa",fontSize:13}}>{hibahItems.length} barang</p><button className="btn bp bs" onClick={()=>{if(!user){setLoginM(true);return}setHibahGive(true)}}>🎁 Beri Hibah</button></div>{hibahItems.length===0?<div style={{textAlign:"center",padding:60,color:"#ccc"}}><div style={{fontSize:48}}>🎁</div><p style={{marginTop:10}}>Belum ada.</p></div>:<div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(280px,1fr))",gap:14}}>{hibahItems.map((h,i)=><div key={h.id} className="card" style={{padding:18}}><div style={{display:"flex",justifyContent:"space-between",marginBottom:8}}><h4 style={{fontFamily:"'Outfit'",fontWeight:700,fontSize:14}}>{h.name}</h4><span className="tag" style={{background:h.status==="available"?"#E8F5E9":"#FFF3E0",color:h.status==="available"?"#2E7D32":"#E65100"}}>{h.status==="available"?"Tersedia":"Diklaim"}</span></div>{h.image_url&&<div style={{marginBottom:8,borderRadius:10,overflow:"hidden"}}><img src={h.image_url} alt={h.name} style={{width:"100%",height:120,objectFit:"cover"}}/></div>}<div style={{fontSize:12,color:"#999",marginBottom:6}}>📦 {h.condition} · 📍 {h.donor?.city||h.city}</div><p style={{fontSize:12.5,color:"#777",lineHeight:1.5,marginBottom:10}}>{h.description}</p><div style={{fontSize:12,color:"#bbb",marginBottom:10}}>🤲 {h.donor?.full_name}</div>{h.status==="available"&&!hibahSent.includes(h.id)?<div style={{display:"flex",gap:6}}><button className="btn bp bs" style={{flex:1}} onClick={()=>{if(!user){setLoginM(true);return}setHibahReq(h.id)}}>Ajukan</button><button className="btn bs" style={{background:"#25D366",color:"white",flex:"0 0 auto"}} onClick={()=>shareWA(`Hibah gratis: ${h.name} (${h.condition})\nDari jamaah di ${h.donor?.city||h.city}\n\nhttps://wargaldii.com/#hibah`)}>📲</button></div>:hibahSent.includes(h.id)?<div className="ok" style={{textAlign:"center"}}>✅ Terkirim!</div>:null}</div>)}</div>}</div>}
{hibahReq!==null&&<div className="modal-bg" onClick={()=>setHibahReq(null)}><div className="modal" onClick={e=>e.stopPropagation()}><button onClick={()=>setHibahReq(null)} style={{position:"absolute",top:12,right:16,background:"none",border:"none",fontSize:17,cursor:"pointer",color:"#ccc"}}>✕</button><h3 className="hmd" style={{marginBottom:12}}>Ajukan Hibah</h3><textarea className="inp" placeholder="Alasan..." style={{minHeight:80}} value={hibahReason} onChange={e=>setHibahReason(e.target.value)}/><button className="btn bp" style={{width:"100%"}} onClick={()=>handleHibahRequest(hibahReq)}>Kirim</button></div></div>}
{hibahGive&&<div className="modal-bg" onClick={()=>setHibahGive(false)}><div className="modal" onClick={e=>e.stopPropagation()}><button onClick={()=>setHibahGive(false)} style={{position:"absolute",top:12,right:16,background:"none",border:"none",fontSize:17,cursor:"pointer",color:"#ccc"}}>✕</button><h3 className="hmd" style={{marginBottom:12}}>🤲 Beri Hibah</h3>
{hibahForm.image_url?<div style={{position:"relative",borderRadius:12,overflow:"hidden",marginBottom:10}}><img src={hibahForm.image_url} alt="" style={{width:"100%",height:140,objectFit:"cover",borderRadius:12}}/><button onClick={()=>setHibahForm(p=>({...p,image_url:""}))} style={{position:"absolute",top:8,right:8,background:"rgba(0,0,0,.5)",color:"white",border:"none",borderRadius:50,width:28,height:28,cursor:"pointer",fontSize:14}}>✕</button></div>
:<label style={{display:"flex",flexDirection:"column",alignItems:"center",padding:"18px 16px",border:"2px dashed #ddd",borderRadius:12,cursor:"pointer",background:"#faf8f5",marginBottom:10}}><span style={{fontSize:28,marginBottom:4}}>📷</span><span style={{fontSize:12,fontWeight:700,color:"#999"}}>Upload foto barang</span><input type="file" accept="image/*" style={{display:"none"}} onChange={async(e)=>{const fl=e.target.files[0];if(!fl)return;if(fl.size>5*1024*1024){showT("Maks 5MB","error");return;}const url=await uploadFile(fl,"hibah");if(url)setHibahForm(p=>({...p,image_url:url}));}}/></label>}
<input className="inp" placeholder="Nama Barang" value={hibahForm.name} onChange={e=>setHibahForm(p=>({...p,name:e.target.value}))}/><select className="sel" value={hibahForm.category} onChange={e=>setHibahForm(p=>({...p,category:e.target.value}))}><option>Elektronik</option><option>Furniture</option><option>Buku</option><option>Pakaian</option><option>Lainnya</option></select><select className="sel" value={hibahForm.condition} onChange={e=>setHibahForm(p=>({...p,condition:e.target.value}))}><option>Sangat Baik (90%+)</option><option>Baik (80%)</option><option>Cukup Baik (70%)</option><option>Layak Pakai (60%)</option></select><textarea className="inp" placeholder="Deskripsi..." style={{minHeight:60}} value={hibahForm.description} onChange={e=>setHibahForm(p=>({...p,description:e.target.value}))}/><input className="inp" placeholder="Kota" value={hibahForm.city} onChange={e=>setHibahForm(p=>({...p,city:e.target.value}))}/><button className="btn bp" style={{width:"100%"}} onClick={handleHibahGive}>Upload →</button></div></div>}

