{showCourseForm&&<div className="modal-bg" onClick={()=>setShowCourseForm(false)}><div className="modal" style={{maxWidth:560}} onClick={e=>e.stopPropagation()}><button onClick={()=>setShowCourseForm(false)} style={{position:"absolute",top:12,right:16,background:"none",border:"none",fontSize:17,cursor:"pointer",color:"#ccc"}}>✕</button><h3 className="hmd" style={{marginBottom:4}}>📚 Buat Kursus</h3><p style={{fontSize:12,color:"#aaa",marginBottom:14}}>Langkah {courseStep}/3</p>{courseStep===1&&<><input className="inp" placeholder="Judul *" value={courseForm.title} onChange={e=>setCourseForm(p=>({...p,title:e.target.value}))}/><textarea className="inp" placeholder="Deskripsi..." style={{minHeight:50}} value={courseForm.description} onChange={e=>setCourseForm(p=>({...p,description:e.target.value}))}/><div style={{display:"flex",gap:8}}><select className="sel" style={{flex:1}} value={courseForm.level} onChange={e=>setCourseForm(p=>({...p,level:e.target.value}))}><option value="pemula">Pemula</option><option value="menengah">Menengah</option><option value="lanjut">Lanjut</option></select><input className="inp" placeholder="Durasi" style={{flex:1}} value={courseForm.duration} onChange={e=>setCourseForm(p=>({...p,duration:e.target.value}))}/></div><button className="btn bp" style={{width:"100%"}} disabled={!courseForm.title} onClick={()=>setCourseStep(2)}>Materi →</button></>}{courseStep===2&&<>{courseMods.map((m,i)=><div key={i} style={{background:"#faf8f5",borderRadius:12,padding:14,marginBottom:10}}><input className="inp" placeholder={`Modul ${i+1} *`} value={m.title} onChange={e=>{const n=[...courseMods];n[i]={...n[i],title:e.target.value};setCourseMods(n)}}/><select className="sel" value={m.type} onChange={e=>{const n=[...courseMods];n[i]={...n[i],type:e.target.value};setCourseMods(n)}}><option value="article">📄 Artikel</option><option value="video">🎬 Video</option></select><textarea className="inp" placeholder="Isi materi..." style={{minHeight:50}} value={m.content} onChange={e=>{const n=[...courseMods];n[i]={...n[i],content:e.target.value};setCourseMods(n)}}/></div>)}<button className="btn bo bs" style={{width:"100%",marginBottom:10}} onClick={()=>setCourseMods(p=>[...p,{title:"",content:"",type:"article",duration:""}])}>+ Modul</button><div style={{display:"flex",gap:8}}><button className="btn bo bs" style={{flex:1}} onClick={()=>setCourseStep(1)}>←</button><button className="btn bp bs" style={{flex:1}} onClick={()=>setCourseStep(3)}>Quiz →</button></div></>}{courseStep===3&&<>{courseQuizzes.map((q,i)=><div key={i} style={{background:"#faf8f5",borderRadius:12,padding:14,marginBottom:10}}><input className="inp" placeholder={`Soal ${i+1}`} value={q.question} onChange={e=>{const n=[...courseQuizzes];n[i]={...n[i],question:e.target.value};setCourseQuizzes(n)}}/>{q.options.map((o,oi)=><div key={oi} style={{display:"flex",gap:6,alignItems:"center",marginBottom:4}}><input type="radio" name={`q${i}`} checked={q.correct_answer===oi} onChange={()=>{const n=[...courseQuizzes];n[i]={...n[i],correct_answer:oi};setCourseQuizzes(n)}}/><input className="inp" placeholder={`Opsi ${String.fromCharCode(65+oi)}`} style={{marginBottom:0,flex:1}} value={o} onChange={e=>{const n=[...courseQuizzes];n[i].options[oi]=e.target.value;setCourseQuizzes(n)}}/></div>)}</div>)}<button className="btn bo bs" style={{width:"100%",marginBottom:10}} onClick={()=>setCourseQuizzes(p=>[...p,{question:"",options:["","","",""],correct_answer:0}])}>+ Soal</button><div style={{display:"flex",gap:8}}><button className="btn bo bs" style={{flex:1}} onClick={()=>setCourseStep(2)}>←</button><button className="btn bp bs" style={{flex:1}} onClick={handleAddCourse}>Publish 🚀</button></div></>}</div></div>}
{showJobForm&&<div className="modal-bg" onClick={()=>setShowJobForm(false)}><div className="modal" onClick={e=>e.stopPropagation()}><button onClick={()=>setShowJobForm(false)} style={{position:"absolute",top:12,right:16,background:"none",border:"none",fontSize:17,cursor:"pointer",color:"#ccc"}}>✕</button><h3 className="hmd" style={{marginBottom:12}}>💼 Buat Lowongan</h3><input className="inp" placeholder="Nama Perusahaan/Usaha *" value={jobForm.company_name} onChange={e=>setJobForm(p=>({...p,company_name:e.target.value}))}/><input className="inp" placeholder="Judul Posisi *" value={jobForm.title} onChange={e=>setJobForm(p=>({...p,title:e.target.value}))}/><textarea className="inp" placeholder="Deskripsi..." style={{minHeight:60}} value={jobForm.description} onChange={e=>setJobForm(p=>({...p,description:e.target.value}))}/><textarea className="inp" placeholder="Persyaratan (satu/baris)" style={{minHeight:80}} value={jobForm.requirements} onChange={e=>setJobForm(p=>({...p,requirements:e.target.value}))}/><div style={{display:"flex",gap:8}}><input className="inp" placeholder="Kota *" style={{flex:1}} value={jobForm.city} onChange={e=>setJobForm(p=>({...p,city:e.target.value}))}/><select className="sel" style={{flex:1}} value={jobForm.type} onChange={e=>setJobForm(p=>({...p,type:e.target.value}))}><option>Full-time</option><option>Part-time</option><option>Freelance</option></select></div><input className="inp" placeholder="Gaji" value={jobForm.salary} onChange={e=>setJobForm(p=>({...p,salary:e.target.value}))}/><button className="btn bp" style={{width:"100%"}} disabled={!jobForm.title||!jobForm.city} onClick={handleAddJob}>Publish →</button></div></div>}
